-- Users_table_with_sample_data.sql\n\n-- Create the Users table schema\nCREATE TABLE Users (\n    UserID INT PRIMARY KEY,\n    UserName VARCHAR(50),\n    UserEmail VARCHAR(100),\n    UserPassword VARCHAR(50),\n    CreatedAt DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Sample INSERT statements for the Users table\nINSERT INTO Users (UserID, UserName, UserEmail, UserPassword) VALUES (1, 'Alice', 'alice@example.com', 'password1');\nINSERT INTO Users (UserID, UserName, UserEmail, UserPassword) VALUES (2, 'Bob', 'bob@example.com', 'password2');\nINSERT INTO Users (UserID, UserName, UserEmail, UserPassword) VALUES (3, 'Charlie', 'charlie@example.com', 'password3');\nINSERT INTO Users (UserID, UserName, UserEmail, UserPassword) VALUES (4, 'David', 'david@example.com', 'password4');\nINSERT INTO Users (UserID, UserName, UserEmail, UserPassword) VALUES (5, 'Eve', 'eve@example.com', 'password5');\n